"use client"
import { Instagram, Youtube, ExternalLink, Users, Heart } from "lucide-react"
import Image from "next/image"
import { useState, useEffect } from "react"

export default function Fantube() {
    const [loading, setLoading] = useState(false)
    const [page, setPage] = useState(1)
    const [youtube, setYoutube] = useState([])



    useEffect(() => {
        setLoading(true)
        const fetchYoutube = async () => {
            const response = await fetch("api/fantube?page=" + page)
            const data = await response.json()
            setYoutube(data)
            setLoading(false)
        }
        fetchYoutube()
    }, [page])




    return (
        <div className="min-h-screen pt-16 bg-gradient-to-br from-purple-50 via-pink-50 to-blue-50">
            <div className="max-w-7xl mx-auto px-8 py-12">
                {/* 헤더 섹션 */}
                <div className="text-center mb-12">
                    <h1 className="text-5xl font-bold text-gray-800 mb-4">
                        Fan Community
                    </h1>
                    <p className="text-xl text-gray-600">
                        프로미스나인 팬들이 운영하는 계정들을 만나보세요
                    </p>
                </div>



                {/* 카드 그리드 */}
                {loading ? <div className="text-center text-black">Loading...</div> : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 text-black">
                        {youtube.length > 0 && youtube.map((item: any) => (
                            <div key={item.id} className="border rounded-lg p-4">
                                <Image
                                    src={item.thumbnail || '/default-thumbnail.jpg'}
                                    width={100}
                                    height={100}
                                    alt={item.channel_name}
                                    className="w-full h-auto object-cover rounded"
                                    onError={(e) => {
                                        e.currentTarget.src = '/default-thumbnail.jpg'
                                    }}
                                />
                                <div className="text-center text-black">{item.channel_name}</div>
                            </div>
                        ))}

                    </div>
                )}

                {/* 페이지네이션 */}
                <div className="flex justify-center gap-4 text-black mt-12">
                    <button onClick={() => setPage(page - 1)} disabled={page === 1}>Previous</button>
                    <div className="text-black">{page}</div>
                    <button onClick={() => setPage(page + 1)}>Next</button>
                </div>
            </div>




            {/* 안내 문구 */}
            <div className="mt-12 text-center">
                <p className="text-gray-500 text-sm">
                    * 자신의 채널을 등록하고 싶다면 아래 링크로 문의해주세요
                </p>
                <a href="https://forms.gle/m4N6YmR914Xh3Hh76" target="_blank" rel="noopener noreferrer" className="text-blue-500 hover:text-blue-600 transition-colors">
                    <ExternalLink className="w-4 h-4 inline-block mr-1" />
                    문의하기
                </a>
            </div>
        </div>
    )
}
